    21→import { Input } from "@/shared/ui/input";
    22→import { toast } from "@/shared/ui/notification";
    23→
    24→const forgotPasswordSchema = z.object({
    25→  code: z.string().length(6, "OTP code must be 6 digits"),
    26→});
    27→
    28→type ForgotPasswordFormData = z.infer<typeof forgotPasswordSchema>;
    29→
    30→export function ForgotPasswordForm() {
    31→  const router = useRouter();
    32→  const searchParams = useSearchParams();
    33→  const email = searchParams.get("email") || "";
    34→  const phone = searchParams.get("phone") || "";
    35→  const [isLoading, setIsLoading] = useState(false);
    36→  const [devOtp, setDevOtp] = useState<string | null>(null);
    37→
    38→  const form = useForm<ForgotPasswordFormData>({
    39→    resolver: zodResolver(forgotPasswordSchema),
    40→    defaultValues: {
    41→      code: "",
    42→    },
    43→  });
    44→
    45→  useEffect(() => {
    46→    const forgotPasswordData = authStorage.forgotPassword.get();
    47→    if (forgotPasswordData?.devOtp) {
    48→      setDevOtp(forgotPasswordData.devOtp);
    49→    }
    50→  }, []);
    51→
    52→  const onSubmit = async (data: ForgotPasswordFormData) => {
    53→    if (!email) {
    54→      toast.error("Missing Email", {
    55→        description: "Please start the password reset process again",
    56→      });
    57→      router.push(APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD);
    58→
    59→      return;
    60→    }
    61→
    62→    setIsLoading(true);
    63→
    64→    try {
    65→      const otpResponse = await verifyOtp({
    66→        email,
    67→        otp: data.code,
    68→        type: OtpType.FORGOT_PASSWORD,
    69→        mediaType: MediaType.EMAIL,
    70→      });
    71→
    72→      authStorage.forgotPasswordCode.set(otpResponse.id);
    73→
    74→      toast.success("Code Verified");
    75→      router.push(APP_ROUTES.AUTH.RESET_PASSWORD);
    76→    } catch {
    77→      toast.error("Invalid Code", {
    78→        description: "Please check the code and try again",
    79→      });
    80→    } finally {
    81→      setIsLoading(false);
    82→    }
    83→  };
    84→
    85→  const handleResend = async () => {
    86→    if (!email) {
    87→      toast.error("Missing Email");
    88→
    89→      return;
    90→    }
    91→
    92→    try {
    93→      const response = await forgotPassword({ email });
    94→      if (response.otp) {
    95→        setDevOtp(response.otp);
    96→        const forgotPasswordData = authStorage.forgotPassword.get();
    97→        if (forgotPasswordData) {
    98→          authStorage.forgotPassword.set({
    99→            ...forgotPasswordData,
   100→            devOtp: response.otp,
   101→          });
   102→        }
   103→        toast.success("Code Generated", {
   104→          description: "Please use the code shown below",
   105→        });
   106→      } else {
   107→        toast.success("Code Resent", {
   108→          description: "Please check your email",
   109→        });
   110→      }
   111→    } catch {
   112→      toast.error("Failed to Resend Code");
   113→    }
   114→  };
   115→
   116→  return (
   117→    <div className="flex w-full flex-col gap-6">
   118→      <h1 className="text-center font-bold font-serif text-lg leading-[1.199em]">
   119→        We sent a Code to your register email {email} & Phone number {phone}
   120→      </h1>
   121→
   122→      <Form {...form}>
   123→        <form
   124→          onSubmit={form.handleSubmit(onSubmit)}
   125→          className="flex w-full flex-col items-center gap-9"
   126→        >
   127→          <div className="flex w-full flex-col items-center justify-center gap-[14px]">
   128→            <FormField
   129→              control={form.control}
   130→              name="code"
   131→              render={({ field }) => (
   132→                <FormItem className="w-full">
   133→                  <FormLabel className="text-lg leading-[1.222em]">
   134→                    Enter code to reset Password
   135→                  </FormLabel>
   136→                  <FormControl>
   137→                    <Input
   138→                      placeholder="Enter 6-digit code"
   139→                      className="h-10"
   140→                      maxLength={6}
   141→                      {...field}
   142→                    />
   143→                  </FormControl>
   144→                  {devOtp && (
   145→                    <div className="mt-2">
   146→                      <DevOtpDisplay otp={devOtp} type="email" />
   147→                    </div>
   148→                  )}
   149→                  <FormMessage />
   150→                </FormItem>
   151→              )}
   152→            />
   153→
   154→            <div className="w-full">
   155→              <button
   156→                type="button"
   157→                onClick={handleResend}
   158→                className="font-serif text-base leading-[1.375em] transition-opacity hover:opacity-70"
   159→              >
   160→                Didn't receive the verification code?{" "}
   161→                <span className="underline">Re-send</span>
   162→              </button>
   163→            </div>
   164→          </div>
   165→
   166→          <Button
   167→            type="submit"
   168→            disabled={isLoading}
   169→            className="w-fit rounded-xl px-[58px] py-[11px] font-bold font-serif text-lg leading-[1.199em]"
   170→          >
   171→            {isLoading ? "Verifying..." : "Submit"}
   172→          </Button>
   173→        </form>
   174→      </Form>
   175→    </div>
   176→  );
   177→}
