    10→import { confirmForgotPassword } from "@/entities/auth/api/services";
    11→import { APP_ROUTES } from "@/shared/config/app-routes";
    12→import { hardPush } from "@/shared/lib/routing/hard-push";
    13→import type { ForgotPasswordStorageData } from "@/shared/lib/storage/auth-storage";
    14→import { authStorage } from "@/shared/lib/storage/auth-storage";
    15→import { Button } from "@/shared/ui/button";
    16→import { Form } from "@/shared/ui/form/form";
    17→import { FormControl } from "@/shared/ui/form/form-control";
    18→import { FormField } from "@/shared/ui/form/form-field";
    19→import { FormItem } from "@/shared/ui/form/form-item";
    20→import { FormLabel } from "@/shared/ui/form/form-label";
    21→import { FormMessage } from "@/shared/ui/form/form-message";
    22→import { toast } from "@/shared/ui/notification";
    23→import { PasswordInput } from "@/shared/ui/password-input";
    24→
    25→const resetPasswordSchema = z
    26→  .object({
    27→    newPassword: z
    28→      .string()
    29→      .min(8, "Password must be at least 8 characters")
    30→      .regex(
    31→        /^(?=.*[A-Za-z])(?=.*\d)/,
    32→        "Password must contain at least one letter and one number",
    33→      ),
    34→    confirmPassword: z.string(),
    35→  })
    36→  .refine((data) => data.newPassword === data.confirmPassword, {
    37→    message: "Passwords do not match",
    38→    path: ["confirmPassword"],
    39→  });
    40→
    41→type ResetPasswordFormData = z.infer<typeof resetPasswordSchema>;
    42→
    43→export function ResetPasswordForm() {
    44→  const router = useRouter();
    45→  const [isLoading, setIsLoading] = useState(false);
    46→  const [forgotPasswordData, setForgotPasswordData] =
    47→    useState<ForgotPasswordStorageData | null>(null);
    48→  const [otpCode, setOtpCode] = useState<string | null>(null);
    49→
    50→  useEffect(() => {
    51→    setForgotPasswordData(authStorage.forgotPassword.get() ?? null);
    52→    setOtpCode(authStorage.forgotPasswordCode.get() ?? null);
    53→  }, []);
    54→
    55→  const form = useForm<ResetPasswordFormData>({
    56→    resolver: zodResolver(resetPasswordSchema),
    57→    defaultValues: {
    58→      newPassword: "",
    59→      confirmPassword: "",
    60→    },
    61→  });
    62→
    63→  const onSubmit = async (data: ResetPasswordFormData) => {
    64→    if (!(forgotPasswordData?.email && otpCode)) {
    65→      toast.error("Missing reset information", {
    66→        description: "Please start the password reset process again",
    67→      });
    68→      router.push(APP_ROUTES.AUTH.REQUEST_FORGOT_PASSWORD);
    69→
    70→      return;
    71→    }
    72→
    73→    setIsLoading(true);
    74→
    75→    try {
    76→      await confirmForgotPassword({
    77→        otpId: otpCode,
    78→        newPassword: data.newPassword,
    79→      });
    80→
    81→      const result = await signIn("credentials", {
    82→        email: forgotPasswordData.email,
    83→        password: data.newPassword,
    84→        redirect: false,
    85→      });
    86→
    87→      if (result?.ok) {
    88→        authStorage.forgotPassword.clear();
    89→        authStorage.forgotPasswordCode.clear();
    90→
    91→        hardPush(APP_ROUTES.PROFILE);
    92→      } else {
    93→        toast.success("Password Reset Successfully", {
    94→          description: "Please sign in with your new password",
    95→        });
    96→        router.push(APP_ROUTES.AUTH.SIGN_IN);
    97→      }
    98→    } catch {
    99→      toast.error("Password Reset Failed", {
   100→        description: "Please try again later",
   101→      });
   102→    } finally {
   103→      setIsLoading(false);
   104→    }
   105→  };
   106→
   107→  return (
   108→    <div className="flex w-full flex-col gap-6">
   109→      <h1 className="text-center font-bold font-serif text-lg leading-[1.199em]">
   110→        Set Your New Password
   111→      </h1>
   112→
   113→      <Form {...form}>
   114→        <form
   115→          onSubmit={form.handleSubmit(onSubmit)}
   116→          className="flex w-full flex-col items-center gap-9"
   117→        >
   118→          <div className="flex w-full flex-col gap-[14px]">
   119→            <FormField
   120→              control={form.control}
   121→              name="newPassword"
   122→              render={({ field }) => (
   123→                <FormItem>
   124→                  <FormLabel className="text-lg leading-[1.222em]">
   125→                    New Password
   126→                  </FormLabel>
   127→                  <FormControl>
   128→                    <PasswordInput placeholder="Password" {...field} />
   129→                  </FormControl>
   130→                  <FormMessage />
   131→                </FormItem>
   132→              )}
   133→            />
   134→
   135→            <div className="w-full rounded-[10px] bg-[#F3F3F3] p-2.5">
   136→              <p className="font-serif text-base leading-[1.375em]">
   137→                Your Password must include
   138→                <br />
   139→                At least 8 characters
   140→                <br />
   141→                At least one letter
   142→                <br />
   143→                At least one number
   144→              </p>
   145→            </div>
   146→
   147→            <FormField
   148→              control={form.control}
   149→              name="confirmPassword"
   150→              render={({ field }) => (
   151→                <FormItem>
   152→                  <FormLabel className="text-lg leading-[1.222em]">
   153→                    Confirm Password
   154→                  </FormLabel>
   155→                  <FormControl>
   156→                    <PasswordInput placeholder="Password" {...field} />
   157→                  </FormControl>
   158→                  <FormMessage />
   159→                </FormItem>
   160→              )}
   161→            />
   162→          </div>
   163→
   164→          <Button
   165→            type="submit"
   166→            disabled={isLoading}
   167→            className="w-fit rounded-xl px-[58px] py-[11px] font-bold font-serif text-lg leading-[1.199em]"
   168→          >
   169→            {isLoading ? "Saving..." : "Save Changes"}
   170→          </Button>
   171→        </form>
   172→      </Form>
   173→    </div>
   174→  );
   175→}
