     3→import type { ClipboardEvent, FC, KeyboardEvent } from "react";
     4→import { memo, useCallback, useRef } from "react";
     5→
     6→import { cn } from "../../lib/ui/cn";
     7→
     8→interface OtpInputProps {
     9→  length?: number;
    10→  value: string;
    11→  onChange: (value: string) => void;
    12→  className?: string;
    13→}
    14→
    15→const OtpInputComponent: FC<OtpInputProps> = ({
    16→  length = 6,
    17→  value,
    18→  onChange,
    19→  className,
    20→}) => {
    21→  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);
    22→
    23→  const handleChange = useCallback(
    24→    (index: number, newValue: string) => {
    25→      // Only allow digits
    26→      const sanitizedValue = newValue.replace(/\D/g, "");
    27→
    28→      if (sanitizedValue.length > 1) {
    29→        // Handle paste - fill all inputs with pasted digits
    30→        const pasteData = sanitizedValue.slice(0, length);
    31→        const newOtp = value.split("");
    32→
    33→        // Fill each input with a digit from pasted data
    34→        for (let i = 0; i < pasteData.length && index + i < length; i += 1) {
    35→          newOtp[index + i] = pasteData[i];
    36→        }
    37→
    38→        onChange(newOtp.join(""));
    39→
    40→        // Focus the last filled input or the next empty one
    41→        const nextIndex = Math.min(index + pasteData.length, length - 1);
    42→        inputRefs.current[nextIndex]?.focus();
    43→        return;
    44→      }
    45→
    46→      // Single character input
    47→      const newOtp = value.split("");
    48→      newOtp[index] = sanitizedValue;
    49→      onChange(newOtp.join(""));
    50→
    51→      // Auto-focus next input
    52→      if (sanitizedValue && index < length - 1) {
    53→        inputRefs.current[index + 1]?.focus();
    54→      }
    55→    },
    56→    [length, value, onChange],
    57→  );
    58→
    59→  const handlePaste = useCallback(
    60→    (index: number, e: ClipboardEvent<HTMLInputElement>) => {
    61→      e.preventDefault();
    62→
    63→      const pastedData = e.clipboardData.getData("text");
    64→      const sanitizedValue = pastedData.replace(/\D/g, "");
    65→
    66→      if (sanitizedValue) {
    67→        const pasteData = sanitizedValue.slice(0, length);
    68→        const newOtp = value.split("");
    69→
    70→        // Fill inputs starting from current index
    71→        for (let i = 0; i < pasteData.length && index + i < length; i += 1) {
    72→          newOtp[index + i] = pasteData[i];
    73→        }
    74→
    75→        onChange(newOtp.join(""));
    76→
    77→        // Focus the last filled input
    78→        const nextIndex = Math.min(index + pasteData.length, length - 1);
    79→        inputRefs.current[nextIndex]?.focus();
    80→      }
    81→    },
    82→    [length, value, onChange],
    83→  );
    84→
    85→  const handleKeyDown = useCallback(
    86→    (index: number, e: KeyboardEvent<HTMLInputElement>) => {
    87→      if (e.key === "Backspace") {
    88→        if (!value[index] && index > 0) {
    89→          // Move to previous input if current is empty
    90→          inputRefs.current[index - 1]?.focus();
    91→        } else {
    92→          // Clear current input
    93→          const newOtp = value.split("");
    94→          newOtp[index] = "";
    95→          onChange(newOtp.join(""));
    96→        }
    97→      } else if (e.key === "ArrowLeft" && index > 0) {
    98→        inputRefs.current[index - 1]?.focus();
    99→      } else if (e.key === "ArrowRight" && index < length - 1) {
   100→        inputRefs.current[index + 1]?.focus();
   101→      }
   102→    },
   103→    [value, onChange, length],
   104→  );
   105→
   106→  return (
   107→    <div className={cn("flex w-full gap-2", className)}>
   108→      {Array.from({ length }).map((_, index) => (
   109→        <input
   110→          key={index}
   111→          ref={(el) => {
   112→            inputRefs.current[index] = el;
   113→          }}
   114→          type="text"
   115→          inputMode="numeric"
   116→          maxLength={1}
   117→          value={value[index] || ""}
   118→          onChange={(e) => handleChange(index, e.target.value)}
   119→          onKeyDown={(e) => handleKeyDown(index, e)}
   120→          onPaste={(e) => handlePaste(index, e)}
   121→          className="flex h-10 w-0 min-w-0 flex-1 items-center justify-center rounded-[10px] border border-input bg-transparent py-[9px] text-center font-serif text-sm leading-[1.2em] transition-colors focus:border-primary focus:outline-none focus:ring-1 focus:ring-primary"
   122→          aria-label={`OTP digit ${index + 1}`}
   123→        />
   124→      ))}
   125→    </div>
   126→  );
   127→};
